import React, { useState } from 'react';
import InventoryItem from '../components/InventoryItem';
import '../styles/inventory.css';

const RoomDetail = ({ room, user, onSave }) => {
    const [items, setItems] = useState(room.inventory);
    const [note, setNote] = useState(room.notes || '');

    const updateCount = (name, delta) => {
        setItems(items.map(item =>
            item.name === name ? { ...item, count: Math.max(0, item.count + delta) } : item
        ));
    };

    const updateDate = (name, newDate) => {
        setItems(items.map(item =>
            item.name === name ? { ...item, expiry: newDate } : item
        ));
    };

    const handleSaveStatus = (status) => {
        const updatedRoom = {
            ...room,
            inventory: items,
            notes: note,
            status: status,
            // Фиксируем дату и время проверки
            lastCleaning: new Date().toLocaleDateString() + ' ' + new Date().toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})
        };
        onSave(updatedRoom);
    };

    return (
        <div className="inventory-container fade-in">
            <div className="room-header-info">
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
                    <h1 style={{margin: 0}}>НОМЕР {room.id}</h1>
                    <span className={`badge ${room.status}`}>{room.status === 'checked' ? 'ПРОВЕРЕНО' : room.status === 'dnd' ? 'DND' : 'ОЖИДАЕТ'}</span>
                </div>
                <p style={{fontSize: '12px', color: '#888', marginTop: '5px'}}>
                    Последняя проверка: {room.lastCleaning || 'Не проверялся'}
                </p>
            </div>

            <div className="product-list">
                {items.map((item, index) => (
                    <InventoryItem
                        key={index}
                        item={item}
                        onUpdate={updateCount}
                        onDateChange={updateDate}
                    />
                ))}
            </div>

            <div style={{marginTop: '20px'}}>
                <label style={{fontSize: '10px', color: '#c5a059', fontWeight: 'bold'}}>ЗАМЕТКИ</label>
                <textarea
                    className="note-area"
                    placeholder="Напишите, если что-то нужно заменить или починить..."
                    value={note}
                    onChange={(e) => setNote(e.target.value)}
                />
            </div>

            <div className="action-block">
                <button className="btn-check" onClick={() => handleSaveStatus('checked')}>
                    СОХРАНИТЬ (ОК)
                </button>
                <button className="btn-dnd" onClick={() => handleSaveStatus('dnd')}>
                    DND / ОТКАЗ
                </button>
            </div>
        </div>
    );
};

export default RoomDetail;
